   191→/**
   192→ * Execute push operation (MMS → Maximo)
   193→ */
   194→async function executePush(
   195→  service: ReturnType<typeof getMaximoSyncService>,
   196→  pmScheduleIds: string[] | undefined,
   197→  context: WorkerJobContext<MaximoSyncJobData>
   198→): Promise<{ pushed: number; errors: number; details?: PushResult[] }> {
