   214→          pushed++;
   215→        } else {
   216→          errors++;
   217→        }
   218→      } catch (error) {
   219→        errors++;
   220→        log.warn({ pmScheduleId: pmId, error }, 'Failed to push PM to Maximo');
   221→      }
   222→    }
   223→
   224→    return { pushed, errors, details };
   225→  }
   226→
   227→  // Otherwise, push all pending changes
   228→  const batchResult = await service.pushAllPending();
   229→  return {
   230→    pushed: batchResult.pushed,
   231→    errors: batchResult.errors,
   232→  };
   233→}
