   238→async function executePull(
   239→  service: ReturnType<typeof getMaximoSyncService>,
   240→  conflictResolution: ConflictResolution | undefined,
   241→  context: WorkerJobContext<MaximoSyncJobData>
   242→): Promise<{ processed: number; updated: number; conflicts: number; details?: PullResult }> {
   243→  await context.updateProgress({ stage: 'PULLING', percent: 60 });
   244→
   245→  const result = await service.pullFromMaximo();
   246→
   247→  // Handle conflicts if any
   248→  if (result.conflicts > 0 && conflictResolution) {
   249→    await context.updateProgress({ stage: 'RESOLVING_CONFLICTS', percent: 80 });
   250→    await context.log(`Resolving ${result.conflicts} conflicts with strategy: ${conflictResolution}`);
   251→
   252→    // Get conflict records and resolve them
   253→    const shadowRecords = await service.listShadowRecords(
   254→      { syncStatus: 'CONFLICT' },
   255→      { page: 1, pageSize: 100 }
   256→    );
   257→
   258→    for (const record of shadowRecords.data) {
   259→      try {
   260→        await service.resolveConflict(record.shadowRecord.pmScheduleId, conflictResolution);
   261→      } catch (error) {
   262→        log.warn(
   263→          { pmScheduleId: record.shadowRecord.pmScheduleId, error },
   264→          'Failed to resolve conflict'
   265→        );
   266→      }
   267→    }
   268→  }
   269→
   270→  return {
   271→    processed: result.processed,
   272→    updated: result.updated,
   273→    conflicts: result.conflicts,
   274→    details: result,
   275→  };
   276→}
   277→
   278→/**
   279→ * Register the Maximo sync worker
   280→ */
   281→export function registerMaximoSyncWorker(): void {
   282→  log.info('Maximo sync worker processor available for registration');
   283→}
