/**
 * MMS Maximo Sync Worker Processor
 *
 * BullMQ job processor for bidirectional synchronization with IBM Maximo.
 * Handles scheduled push/pull operations and conflict resolution.
 *
 * Job Flow:
 * 1. Receive MaximoSyncJobData from queue
 * 2. Based on operation type:
 *    - push: Send pending MMS changes to Maximo
 *    - pull: Fetch remote changes from Maximo
 *    - full: Execute both push and pull
 * 3. Handle conflicts according to resolution strategy
 * 4. Store sync history and update shadow records
 *
 * @see specs/007-integration.md Section 7.4
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type MaximoSyncJobData } from '../../lib/queue';
import {
  getMaximoSyncService,
  type PushResult,
  type PullResult,
  type ConflictResolution,
} from '../../services';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'maximo-sync' });

// =============================================================================
// Result Types
// =============================================================================

interface MaximoSyncResult {
  operation: 'push' | 'pull' | 'full';
  push?: {
    pushed: number;
    errors: number;
    details?: PushResult[];
  };
  pull?: {
    processed: number;
    updated: number;
    conflicts: number;
    details?: PullResult;
  };
  durationMs: number;
  success: boolean;
}

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process Maximo sync job
 *
 * Executes bidirectional synchronization between MMS and Maximo.
 * Supports push (MMS→Maximo), pull (Maximo→MMS), or full (both) operations.
 */
export async function processMaximoSyncJob(
  context: WorkerJobContext<MaximoSyncJobData>
): Promise<MaximoSyncResult> {
  return withSpan('worker.maximo_sync.process', async (span) => {
    const { id, data } = context;
    const { operation, pmScheduleIds, depotId, force, conflictResolution } = data;
    const startTime = Date.now();

    span.setAttribute('jobId', id);
    span.setAttribute('operation', operation);
    span.setAttribute('hasSpecificPms', !!pmScheduleIds);
    span.setAttribute('depotId', depotId ?? 'all');
    span.setAttribute('force', force ?? false);

    log.info(
      { jobId: id, operation, pmScheduleIds: pmScheduleIds?.length, depotId, force },
      'Processing Maximo sync job'
    );

    const result: MaximoSyncResult = {
      operation,
      durationMs: 0,
      success: true,
    };

    const maximoService = getMaximoSyncService();

    try {
      // Execute push operation
      if (operation === 'push' || operation === 'full') {
        await context.updateProgress({ stage: 'PUSHING', percent: 10 });
        await context.log('Starting push sync (MMS → Maximo)');

        const pushResult = await executePush(
          maximoService,
          pmScheduleIds,
          context
        );

        result.push = pushResult;

        log.info(
          { jobId: id, pushed: pushResult.pushed, errors: pushResult.errors },
          'Push sync complete'
        );
      }

      // Execute pull operation
      if (operation === 'pull' || operation === 'full') {
        const progressBase = operation === 'full' ? 50 : 10;
        await context.updateProgress({ stage: 'PULLING', percent: progressBase });
        await context.log('Starting pull sync (Maximo → MMS)');

        const pullResult = await executePull(
          maximoService,
          conflictResolution as ConflictResolution | undefined,
          context
        );

        result.pull = pullResult;

        log.info(
          {
            jobId: id,
            processed: pullResult.processed,
            updated: pullResult.updated,
            conflicts: pullResult.conflicts,
          },
          'Pull sync complete'
        );
      }

      // Calculate duration
      result.durationMs = Date.now() - startTime;

      // Determine overall success
      result.success =
        (result.push?.errors ?? 0) === 0 && (result.pull?.conflicts ?? 0) === 0;

      // Update progress: complete
      await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

      // Log summary
      await context.log(
        `Sync complete: ${result.push?.pushed ?? 0} pushed, ` +
          `${result.pull?.updated ?? 0} updated, ` +
          `${result.pull?.conflicts ?? 0} conflicts, ` +
          `${result.durationMs}ms`
      );

      // Record metrics
      span.setAttribute('maximo.pushed', result.push?.pushed ?? 0);
      span.setAttribute('maximo.pushErrors', result.push?.errors ?? 0);
      span.setAttribute('maximo.pulled', result.pull?.processed ?? 0);
      span.setAttribute('maximo.updated', result.pull?.updated ?? 0);
      span.setAttribute('maximo.conflicts', result.pull?.conflicts ?? 0);
      span.setAttribute('maximo.durationMs', result.durationMs);
      span.setAttribute('maximo.success', result.success);

      log.info(
        {
          jobId: id,
          operation,
          success: result.success,
          durationMs: result.durationMs,
        },
        'Maximo sync job complete'
      );

      return result;
    } catch (error) {
      result.durationMs = Date.now() - startTime;
      result.success = false;

      log.error(
        { jobId: id, error, durationMs: result.durationMs },
        'Maximo sync job failed'
      );

      throw error;
    }
  });
}

/**
 * Execute push operation (MMS → Maximo)
 */
async function executePush(
  service: ReturnType<typeof getMaximoSyncService>,
  pmScheduleIds: string[] | undefined,
  context: WorkerJobContext<MaximoSyncJobData>
): Promise<{ pushed: number; errors: number; details?: PushResult[] }> {
  // If specific PM IDs provided, push them individually
  if (pmScheduleIds && pmScheduleIds.length > 0) {
    const details: PushResult[] = [];
    let pushed = 0;
    let errors = 0;

    for (let i = 0; i < pmScheduleIds.length; i++) {
      const pmId = pmScheduleIds[i];
      const progress = 10 + Math.floor((i / pmScheduleIds.length) * 40);
      await context.updateProgress({ stage: 'PUSHING', percent: progress, current: i + 1, total: pmScheduleIds.length });

      try {
        const result = await service.pushToMaximo(pmId);
        details.push(result);
        if (result.action === 'CREATED' || result.action === 'UPDATED') {
          pushed++;
        } else {
          errors++;
        }
      } catch (error) {
        errors++;
        log.warn({ pmScheduleId: pmId, error }, 'Failed to push PM to Maximo');
      }
    }

    return { pushed, errors, details };
  }

  // Otherwise, push all pending changes
  const batchResult = await service.pushAllPending();
  return {
    pushed: batchResult.pushed,
    errors: batchResult.errors,
  };
}

/**
 * Execute pull operation (Maximo → MMS)
 */
async function executePull(
  service: ReturnType<typeof getMaximoSyncService>,
  conflictResolution: ConflictResolution | undefined,
  context: WorkerJobContext<MaximoSyncJobData>
): Promise<{ processed: number; updated: number; conflicts: number; details?: PullResult }> {
  await context.updateProgress({ stage: 'PULLING', percent: 60 });

  const result = await service.pullFromMaximo();

  // Handle conflicts if any
  if (result.conflicts > 0 && conflictResolution) {
    await context.updateProgress({ stage: 'RESOLVING_CONFLICTS', percent: 80 });
    await context.log(`Resolving ${result.conflicts} conflicts with strategy: ${conflictResolution}`);

    // Get conflict records and resolve them
    const shadowRecords = await service.listShadowRecords(
      { syncStatus: 'CONFLICT' },
      { page: 1, pageSize: 100 }
    );

    for (const record of shadowRecords.data) {
      try {
        await service.resolveConflict(record.shadowRecord.pmScheduleId, conflictResolution);
      } catch (error) {
        log.warn(
          { pmScheduleId: record.shadowRecord.pmScheduleId, error },
          'Failed to resolve conflict'
        );
      }
    }
  }

  return {
    processed: result.processed,
    updated: result.updated,
    conflicts: result.conflicts,
    details: result,
  };
}

/**
 * Register the Maximo sync worker
 */
export function registerMaximoSyncWorker(): void {
  log.info('Maximo sync worker processor available for registration');
}

