   750→  /**
   751→   * Push all pending changes to Maximo (batch sync)
   752→   */
   753→  async pushAllPending(): Promise<{ pushed: number; errors: number }> {
   754→    return this.traced('pushAllPending', async (span) => {
   755→      // Get all pending shadow records
   756→      const pending = await this.db.query.maximoShadowRecords.findMany({
   757→        where: or(
   758→          eq(maximoShadowRecords.syncStatus, 'PENDING'),
   759→          and(
   760→            eq(maximoShadowRecords.syncStatus, 'ERROR'),
   761→            lt(maximoShadowRecords.syncAttempts, 5),
   762→            or(
   763→              isNull(maximoShadowRecords.nextSyncAt),
   764→              lt(maximoShadowRecords.nextSyncAt, new Date())
   765→            )
   766→          )
   767→        ),
   768→        limit: 100, // Process in batches
   769→      });
   770→
   771→      span.setAttribute('pending.count', pending.length);
   772→
   773→      let pushed = 0;
   774→      let errors = 0;
   775→
   776→      for (const record of pending) {
   777→        try {
   778→          const result = await this.pushToMaximo(record.pmScheduleId);
   779→          if (result.action === 'CREATED' || result.action === 'UPDATED') {
   780→            pushed++;
   781→          } else if (result.action === 'ERROR') {
   782→            errors++;
   783→          }
   784→        } catch (error) {
   785→          errors++;
   786→          this.log.error(
   787→            { pmScheduleId: record.pmScheduleId, error },
   788→            'Failed to push to Maximo'
   789→          );
   790→        }
   791→      }
   792→
   793→      span.setAttribute('pushed.count', pushed);
   794→      span.setAttribute('errors.count', errors);
   795→
   796→      return { pushed, errors };
   797→    });
   798→  }
