/**
 * MMS Maximo Sync Service
 *
 * Implements bidirectional synchronization between MMS and IBM Maximo CMMS.
 * Uses the shadow record pattern to enable offline operation and conflict resolution.
 *
 * Key responsibilities:
 * - Create and manage shadow records for PM schedules
 * - Push MMS changes to Maximo (create/update work orders)
 * - Pull Maximo status changes to MMS
 * - Detect and resolve conflicts
 * - Validate edit operations against Maximo status locks
 *
 * Integration flow:
 * 1. When a PM is scheduled in MMS, a shadow record is created (status: PENDING)
 * 2. Sync job pushes shadow records to Maximo (creates work orders)
 * 3. Maximo status changes (via polling or webhook) update shadow records
 * 4. INPRG/COMP/CLOSE/CAN status locks PM in MMS (read-only)
 *
 * @see specs/007-integration.md Section 7.4
 */

import { eq, and, desc, sql, inArray, lt, isNull, or, count, type SQL } from 'drizzle-orm';
import { addDays, addSeconds, format } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  maximoShadowRecords,
  maximoSyncHistory,
  pmSchedule,
  type MaximoShadowRecord,
  type PmScheduleRecord,
} from '../lib/db/schema';
import {
  MaximoConnectionError,
  NotFoundError,
  ValidationError,
} from '../lib/errors';
import { CircuitBreaker } from '../lib/utils/resilience';

// =============================================================================
// Types
// =============================================================================

/** Maximo work order status values */
export type MaximoWoStatus = 'WAPPR' | 'APPR' | 'INPRG' | 'COMP' | 'CLOSE' | 'CAN';

/** MMS sync status values */
export type SyncStatus = 'PENDING' | 'SYNCED' | 'CONFLICT' | 'ERROR';

/** Sync operation type */
export type SyncOperation = 'PUSH' | 'PULL' | 'CONFLICT_RESOLVE';

/** MMS PM status type */
export type MmsPmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';

/** Status mapping from Maximo to MMS */
export const MAXIMO_TO_MMS_STATUS: Record<MaximoWoStatus, MmsPmStatus> = {
  WAPPR: 'SCHEDULED',
  APPR: 'SCHEDULED',
  INPRG: 'IN_PROGRESS',
  COMP: 'COMPLETED',
  CLOSE: 'COMPLETED',
  CAN: 'CANCELLED',
};

/** Locked Maximo statuses (PM cannot be edited in MMS) */
export const LOCKED_MAXIMO_STATUSES: MaximoWoStatus[] = ['INPRG', 'COMP', 'CLOSE', 'CAN'];

/** Human-readable status labels */
export const MAXIMO_STATUS_LABELS: Record<MaximoWoStatus, string> = {
  WAPPR: 'Waiting Approval',
  APPR: 'Approved',
  INPRG: 'In Progress',
  COMP: 'Completed',
  CLOSE: 'Closed',
  CAN: 'Cancelled',
};

/** Edit validation result */
export interface EditValidationResult {
  valid: boolean;
  reason?: 'MAXIMO_STATUS_LOCK' | 'SYNC_CONFLICT' | 'BASELINE_LOCK' | 'NOT_FOUND';
  message?: string;
  maximoStatus?: string;
  maximoWoNum?: string;
  suggestion?: string;
}

/** Push sync result */
export interface PushResult {
  action: 'CREATED' | 'UPDATED' | 'SKIPPED' | 'CONFLICT' | 'ERROR';
  woNum?: string;
  reason?: string;
  error?: string;
}

/** Pull sync result */
export interface PullResult {
  processed: number;
  updated: number;
  conflicts: number;
  errors: number;
  details: PullDetail[];
}

export interface PullDetail {
  pmScheduleId: string;
  maximoWoNum: string;
  previousStatus?: string;
  newStatus?: string;
  action: 'UPDATED' | 'CONFLICT' | 'ERROR' | 'SKIPPED';
  error?: string;
}

/** Conflict resolution strategy */
export type ConflictResolution = 'USE_MMS' | 'USE_MAXIMO';

/** Shadow record with related data */
export interface ShadowRecordWithPm {
  shadowRecord: MaximoShadowRecord;
  pmSchedule: PmScheduleRecord & {
    train?: { id: string; trainNumber: string };
    pmType?: { id: string; pmCode: string; pmName: string };
    depot?: { id: string; code: string };
  };
}

/** Maximo work order create payload */
export interface MaximoWorkOrderCreate {
  siteid: string;
  woclass: string;
  worktype: string;
  assetnum: string;
  description: string;
  schedstart: string;
  schedfinish: string;
  location?: string;
  estlabhrs?: number;
  pmnum?: string;
  mms_schedule_id: string;
  mms_constraint_start: string;
  mms_constraint_end: string;
}

/** Maximo work order response */
export interface MaximoWorkOrder {
  wonum: string;
  status: MaximoWoStatus;
  schedstart?: string;
  schedfinish?: string;
  actstart?: string;
  actfinish?: string;
  actlabhrs?: number;
  changedate?: string;
}

/** Sync statistics */
export interface SyncStats {
  pendingRecords: number;
  syncedRecords: number;
  conflictRecords: number;
  errorRecords: number;
  lastSyncAt?: Date;
  lastPullAt?: Date;
  circuitBreakerState: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
}

/** Query filters for shadow records */
export interface ShadowRecordFilters {
  syncStatus?: SyncStatus | SyncStatus[];
  pmScheduleId?: string;
  maximoWoNum?: string;
  hasConflict?: boolean;
  needsSync?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
}

/** Paginated result */
export interface PaginatedShadowRecords {
  data: ShadowRecordWithPm[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: MaximoSyncService | null = null;

/**
 * Get the singleton MaximoSyncService instance
 */
export function getMaximoSyncService(): MaximoSyncService {
  if (!instance) {
    instance = new MaximoSyncService();
  }
  return instance;
}

// =============================================================================
// MaximoSyncService Implementation
// =============================================================================

/**
 * Maximo Sync Service for bidirectional PM synchronization
 *
 * Implements the shadow record pattern from spec 007.4.2:
 * - MMS is source of truth for scheduling
 * - Shadow records track sync state with Maximo
 * - Status-based locking prevents conflicts
 *
 * @example
 * ```typescript
 * const maximoSync = getMaximoSyncService();
 *
 * // Validate before editing a PM
 * const validation = await maximoSync.validateEdit(pmId);
 * if (!validation.valid) {
 *   throw new MaximoLockError(validation.message);
 * }
 *
 * // Create shadow record for new PM
 * await maximoSync.createShadowRecord(pmId);
 *
 * // Push changes to Maximo
 * const result = await maximoSync.pushToMaximo(pmId);
 *
 * // Pull status updates from Maximo
 * await maximoSync.pullFromMaximo();
 * ```
 */
export class MaximoSyncService extends BaseService {
  private readonly circuitBreaker: CircuitBreaker;
  private lastPullTimestamp: Date | null = null;

  constructor() {
    super({ name: 'maximo-sync-service' });

    // Circuit breaker for Maximo API calls
    this.circuitBreaker = new CircuitBreaker(
      {
        failureThreshold: 5,
        successThreshold: 2,
        resetTimeoutMs: 60000, // 60 seconds in open state
        isFailure: (error) => {
          // Only count network/availability errors as circuit breaker failures
          if (error instanceof MaximoConnectionError) return true;
          if (error instanceof Error) {
            const msg = error.message.toLowerCase();
            return (
              msg.includes('econnrefused') ||
              msg.includes('etimedout') ||
              msg.includes('econnreset') ||
              msg.includes('503') ||
              msg.includes('504')
            );
          }
          return false;
        },
      },
      'maximo-sync'
    );
  }

  // ===========================================================================
  // Edit Validation
  // ===========================================================================

  /**
   * Validate PM edit request against Maximo status
   *
   * MUST be called before any PM schedule modification.
   * Prevents race conditions where a planner reschedules a PM that
   * technicians are actively working on.
   *
   * @see specs/007-integration.md Section 7.4.6
   */
  async validateEdit(pmScheduleId: string): Promise<EditValidationResult> {
    return this.traced('validateEdit', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);

      // Get PM with shadow record
      const pm = await this.getPmWithShadow(pmScheduleId);

      if (!pm) {
        return {
          valid: false,
          reason: 'NOT_FOUND',
          message: 'PM schedule not found',
        };
      }

      // Check 1: Maximo status lock
      if (pm.shadowRecord?.maximoData) {
        const maximoData = pm.shadowRecord.maximoData as { status?: string };
        const maximoStatus = maximoData.status as MaximoWoStatus | undefined;

        if (maximoStatus && LOCKED_MAXIMO_STATUSES.includes(maximoStatus)) {
          span.setAttribute('maximo.status', maximoStatus);
          span.setAttribute('maximo.locked', true);

          return {
            valid: false,
            reason: 'MAXIMO_STATUS_LOCK',
            message: `Cannot modify: Work order is ${MAXIMO_STATUS_LABELS[maximoStatus]} in Maximo`,
            maximoStatus,
            maximoWoNum: pm.shadowRecord.maximoWoNum ?? undefined,
            suggestion:
              maximoStatus === 'INPRG'
                ? 'Wait for technicians to complete work, or contact supervisor to cancel in Maximo first'
                : 'This PM has been completed/cancelled. Create a new PM if rescheduling is needed.',
          };
        }
      }

      // Check 2: Pending sync conflict
      if (pm.shadowRecord?.syncStatus === 'CONFLICT') {
        span.setAttribute('sync.conflict', true);

        return {
          valid: false,
          reason: 'SYNC_CONFLICT',
          message: 'Unresolved sync conflict exists. Resolve before editing.',
          suggestion: 'Go to Integration > Conflicts to resolve',
        };
      }

      // Check 3: Baseline lock (if PM is locked)
      if (pm.pmSchedule.isLocked) {
        span.setAttribute('baseline.locked', true);

        return {
          valid: false,
          reason: 'BASELINE_LOCK',
          message: 'PM is locked in published baseline',
          suggestion: 'Unlock in baseline editor or create scenario to test changes',
        };
      }

      span.setAttribute('edit.valid', true);
      return { valid: true };
    });
  }

  /**
   * Check if a PM is locked by Maximo status
   */
  async isMaximoLocked(pmScheduleId: string): Promise<boolean> {
    const validation = await this.validateEdit(pmScheduleId);
    return validation.reason === 'MAXIMO_STATUS_LOCK';
  }

