  /**
   * List shadow records with filters
   */
  async listShadowRecords(
    filters: ShadowRecordFilters = {},
    pagination: PaginationOptions = {}
  ): Promise<PaginatedShadowRecords> {
    return this.traced('listShadowRecords', async (span) => {
      const { page = 1, pageSize = 50 } = pagination;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: SQL<unknown>[] = [];

      if (filters.syncStatus) {
        const statuses = Array.isArray(filters.syncStatus)
          ? filters.syncStatus
          : [filters.syncStatus];
        conditions.push(inArray(maximoShadowRecords.syncStatus, statuses));
      }

      if (filters.pmScheduleId) {
        conditions.push(eq(maximoShadowRecords.pmScheduleId, filters.pmScheduleId));
      }

      if (filters.maximoWoNum) {
        conditions.push(eq(maximoShadowRecords.maximoWoNum, filters.maximoWoNum));
      }

      if (filters.hasConflict) {
        conditions.push(eq(maximoShadowRecords.syncStatus, 'CONFLICT'));
      }

      if (filters.needsSync) {
        const needsSyncCondition = or(
          eq(maximoShadowRecords.syncStatus, 'PENDING'),
          and(
            eq(maximoShadowRecords.syncStatus, 'ERROR'),
            lt(maximoShadowRecords.syncAttempts, 5)
          )
        );
        if (needsSyncCondition) {
          conditions.push(needsSyncCondition);
        }
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ value: total }] = await this.db
        .select({ value: count() })
        .from(maximoShadowRecords)
        .where(whereClause);

      // Get records
      const records = await this.db.query.maximoShadowRecords.findMany({
        where: whereClause,
        orderBy: [desc(maximoShadowRecords.updatedAt)],
        limit: pageSize,
        offset,
        with: {
          pmScheduleEntry: {
            with: {
              train: true,
              pmType: true,
              assignedDepot: true,
            },
          },
        },
      });

      // Transform to ShadowRecordWithPm
      const data: ShadowRecordWithPm[] = records.map((r) => ({
        shadowRecord: r,
        pmSchedule: {
          ...r.pmScheduleEntry,
          train: r.pmScheduleEntry.train
            ? {
                id: r.pmScheduleEntry.train.id,
                trainNumber: r.pmScheduleEntry.train.trainNumber,
              }
            : undefined,
          pmType: r.pmScheduleEntry.pmType
            ? {
                id: r.pmScheduleEntry.pmType.id,
                pmCode: r.pmScheduleEntry.pmType.pmCode,
                pmName: r.pmScheduleEntry.pmType.pmName,
              }
            : undefined,
          depot: r.pmScheduleEntry.assignedDepot
            ? {
                id: r.pmScheduleEntry.assignedDepot.id,
                code: r.pmScheduleEntry.assignedDepot.code,
              }
            : undefined,
        },
      }));

      span.setAttribute('query.total', total);
      span.setAttribute('query.returned', data.length);

      return {
        data,
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      };
    });
  }

  // ===========================================================================
  // Push Sync (MMS → Maximo)
  // ===========================================================================

  /**
   * Push MMS changes to Maximo for a specific PM
   *
   * Creates or updates the Maximo work order based on shadow record state.
   *
   * @see specs/007-integration.md Section 7.4.7
   */
  async pushToMaximo(pmScheduleId: string): Promise<PushResult> {
    return this.traced('pushToMaximo', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);

      const pmWithShadow = await this.getPmWithShadow(pmScheduleId);

      if (!pmWithShadow) {
        return { action: 'ERROR', error: 'PM schedule not found' };
      }

      const { pmSchedule: pm, shadowRecord } = pmWithShadow;

      // Create shadow record if doesn't exist
      let shadow = shadowRecord;
      if (!shadow?.id) {
        shadow = await this.createShadowRecord(pmScheduleId);
      }

      // Check circuit breaker state
      if (this.circuitBreaker.getState() === 'OPEN') {
        this.log.warn({ pmScheduleId }, 'Circuit breaker is open, skipping push');
        return { action: 'SKIPPED', reason: 'Circuit breaker open' };
      }

      const syncAttempts = shadow.syncAttempts ?? 0;

      try {
        // No Maximo WO yet - create new
        if (!shadow.maximoWoNum) {
          // Use circuit breaker for Maximo API call
          const woNum = await this.circuitBreaker.execute(() =>
            this.createMaximoWorkOrder(pm)
          );

          await this.updateShadowRecord(shadow.id, {
            maximoWoNum: woNum,
            syncStatus: 'SYNCED',
            lastSyncAt: new Date(),
            lastSyncError: null,
            syncAttempts: syncAttempts + 1,
            mmsDataSnapshot: this.createMmsSnapshot(pm),
          });

          await this.recordSyncHistory(shadow.id, 'PUSH', {
            previousStatus: shadow.syncStatus,
            newStatus: 'SYNCED',
            success: true,
          });

          span.setAttribute('maximo.wo.created', woNum);

          return { action: 'CREATED', woNum };
        }

        // Check if Maximo WO is in locked state
        const maximoWo = await this.circuitBreaker.execute(() =>
          this.fetchMaximoWorkOrder(shadow.maximoWoNum!)
        );

        if (maximoWo && LOCKED_MAXIMO_STATUSES.includes(maximoWo.status)) {
          return {
            action: 'SKIPPED',
            reason: `Work order is ${MAXIMO_STATUS_LABELS[maximoWo.status]}`,
            woNum: shadow.maximoWoNum,
          };
        }

        // Check for conflicts
        if (maximoWo?.changedate && shadow.lastSyncAt) {
          const maximoChangeDate = new Date(maximoWo.changedate);
          if (maximoChangeDate > shadow.lastSyncAt) {
            await this.updateShadowRecord(shadow.id, {
              syncStatus: 'CONFLICT',
              maximoData: {
                status: maximoWo.status,
                schedStart: maximoWo.schedstart,
                schedFinish: maximoWo.schedfinish,
                actualStart: maximoWo.actstart,
                actualFinish: maximoWo.actfinish,
                actualLabor: maximoWo.actlabhrs,
                changeDate: maximoWo.changedate,
              },
            });

            await this.recordSyncHistory(shadow.id, 'PUSH', {
              previousStatus: shadow.syncStatus,
              newStatus: 'CONFLICT',
              success: false,
              errorMessage: 'Conflict detected - Maximo changed after last sync',
            });

            return { action: 'CONFLICT', woNum: shadow.maximoWoNum };
          }
        }

        // Update existing work order
        await this.circuitBreaker.execute(() =>
          this.updateMaximoWorkOrder(shadow.maximoWoNum!, pm)
        );

        await this.updateShadowRecord(shadow.id, {
          syncStatus: 'SYNCED',
          lastSyncAt: new Date(),
          lastSyncError: null,
          syncAttempts: syncAttempts + 1,
          mmsDataSnapshot: this.createMmsSnapshot(pm),
          pendingChanges: null,
        });

        await this.recordSyncHistory(shadow.id, 'PUSH', {
          previousStatus: shadow.syncStatus,
          newStatus: 'SYNCED',
          success: true,
        });

        span.setAttribute('maximo.wo.updated', shadow.maximoWoNum);

        return { action: 'UPDATED', woNum: shadow.maximoWoNum };
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);

        await this.updateShadowRecord(shadow.id, {
          syncStatus: 'ERROR',
          lastSyncError: errorMessage,
          syncAttempts: syncAttempts + 1,
          nextSyncAt: this.calculateNextRetry(syncAttempts + 1),
        });

        await this.recordSyncHistory(shadow.id, 'PUSH', {
          previousStatus: shadow.syncStatus,
          newStatus: 'ERROR',
          success: false,
          errorMessage,
        });

        span.setAttribute('error', true);
        span.setAttribute('error.message', errorMessage);

        return { action: 'ERROR', error: errorMessage };
      }
    });
  }

  /**
   * Push all pending changes to Maximo (batch sync)
   */
  async pushAllPending(): Promise<{ pushed: number; errors: number }> {
    return this.traced('pushAllPending', async (span) => {
      // Get all pending shadow records
      const pending = await this.db.query.maximoShadowRecords.findMany({
        where: or(
          eq(maximoShadowRecords.syncStatus, 'PENDING'),
          and(
            eq(maximoShadowRecords.syncStatus, 'ERROR'),
            lt(maximoShadowRecords.syncAttempts, 5),
            or(
              isNull(maximoShadowRecords.nextSyncAt),
              lt(maximoShadowRecords.nextSyncAt, new Date())
            )
          )
        ),
        limit: 100, // Process in batches
      });

      span.setAttribute('pending.count', pending.length);

      let pushed = 0;
      let errors = 0;

      for (const record of pending) {
        try {
          const result = await this.pushToMaximo(record.pmScheduleId);
          if (result.action === 'CREATED' || result.action === 'UPDATED') {
            pushed++;
          } else if (result.action === 'ERROR') {
            errors++;
          }
        } catch (error) {
          errors++;
          this.log.error(
            { pmScheduleId: record.pmScheduleId, error },
            'Failed to push to Maximo'
          );
        }
      }

      span.setAttribute('pushed.count', pushed);
      span.setAttribute('errors.count', errors);

      return { pushed, errors };
    });
  }

  // ===========================================================================
  // Pull Sync (Maximo → MMS)
  // ===========================================================================

  /**
   * Pull Maximo status changes to MMS
   *
   * Queries Maximo for work orders modified since last pull and updates
   * MMS PM statuses accordingly.
   *
   * @see specs/007-integration.md Section 7.4.7
   */
  async pullFromMaximo(): Promise<PullResult> {
    return this.traced('pullFromMaximo', async (span) => {
      const result: PullResult = {
        processed: 0,
        updated: 0,
        conflicts: 0,
        errors: 0,
        details: [],
      };

      // Check circuit breaker state
      if (this.circuitBreaker.getState() === 'OPEN') {
        this.log.warn('Circuit breaker is open, skipping pull');
        return result;
      }

      // Get all synced shadow records
      const syncedRecords = await this.db.query.maximoShadowRecords.findMany({
        where: and(
          eq(maximoShadowRecords.syncStatus, 'SYNCED'),
          sql`${maximoShadowRecords.maximoWoNum} IS NOT NULL`
        ),
      });

      span.setAttribute('synced.records', syncedRecords.length);

      for (const record of syncedRecords) {
        result.processed++;

        try {
          if (!record.maximoWoNum) continue;

          // Use circuit breaker for Maximo API call
          const maximoWo = await this.circuitBreaker.execute(() =>
            this.fetchMaximoWorkOrder(record.maximoWoNum!)
          );

          if (!maximoWo) {
            result.details.push({
              pmScheduleId: record.pmScheduleId,
              maximoWoNum: record.maximoWoNum,
              action: 'SKIPPED',
              error: 'Work order not found in Maximo',
            });
            continue;
          }

          const currentMaximoData = record.maximoData as { status?: string } | null;
          const previousStatus = currentMaximoData?.status;

          // Status changed
          if (maximoWo.status !== previousStatus) {
            await this.handleStatusChange(record, maximoWo);
            result.updated++;
            result.details.push({
              pmScheduleId: record.pmScheduleId,
              maximoWoNum: record.maximoWoNum,
              previousStatus,
              newStatus: maximoWo.status,
              action: 'UPDATED',
            });
          }

          // Record actuals if completed
          if (
            (maximoWo.status === 'COMP' || maximoWo.status === 'CLOSE') &&
            maximoWo.actlabhrs
          ) {
            await this.recordActuals(record.pmScheduleId, maximoWo);
          }
        } catch (error) {
          result.errors++;
          result.details.push({
            pmScheduleId: record.pmScheduleId,
            maximoWoNum: record.maximoWoNum ?? '',
            action: 'ERROR',
            error: error instanceof Error ? error.message : String(error),
          });
        }
      }

      this.lastPullTimestamp = new Date();
      span.setAttribute('pull.updated', result.updated);
      span.setAttribute('pull.errors', result.errors);

      return result;
    });
  }

  // ===========================================================================
  // Conflict Resolution
  // ===========================================================================

  /**
   * Resolve sync conflict
   *
   * @param pmScheduleId - PM schedule ID with conflict
   * @param resolution - Strategy: USE_MMS (force push) or USE_MAXIMO (apply Maximo data)
   * @param userId - User resolving the conflict
   */
  async resolveConflict(
    pmScheduleId: string,
    resolution: ConflictResolution,
    userId?: string
  ): Promise<void> {
    return this.traced('resolveConflict', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
      span.setAttribute('resolution', resolution);

      const shadow = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
      });

      if (!shadow) {
        throw new NotFoundError(`Shadow record not found for PM: ${pmScheduleId}`, {
          entityType: 'MaximoShadowRecord',
          entityId: pmScheduleId,
        });
      }

      if (shadow.syncStatus !== 'CONFLICT') {
        throw new ValidationError('Shadow record is not in conflict state');
      }

      if (!shadow.maximoWoNum) {
        throw new ValidationError('Shadow record has no Maximo work order');
      }

      if (resolution === 'USE_MMS') {
        // Force push MMS data to Maximo
        const pm = await this.db.query.pmSchedule.findFirst({
          where: eq(pmSchedule.id, pmScheduleId),
          with: { train: true, pmType: true, assignedDepot: true },
        });

        if (!pm) {
          throw new NotFoundError(`PM schedule not found: ${pmScheduleId}`, {
            entityType: 'PmSchedule',
            entityId: pmScheduleId,
          });
        }

        await this.updateMaximoWorkOrder(shadow.maximoWoNum, pm, { force: true });
      } else {
        // Apply Maximo data to MMS
        const maximoWo = await this.fetchMaximoWorkOrder(shadow.maximoWoNum);

        if (!maximoWo) {
          throw new MaximoConnectionError('Failed to fetch Maximo work order');
        }

        await this.applyMaximoDataToMms(pmScheduleId, maximoWo);
      }

      // Update shadow record
      await this.updateShadowRecord(shadow.id, {
        syncStatus: 'SYNCED',
        lastSyncAt: new Date(),
        conflictResolvedAt: new Date(),
        conflictResolvedBy: userId ?? undefined,
        conflictResolution: resolution,
      });

      await this.recordSyncHistory(shadow.id, 'CONFLICT_RESOLVE', {
        previousStatus: 'CONFLICT',
        newStatus: 'SYNCED',
        success: true,
      });

      this.log.info(
        { pmScheduleId, resolution, userId },
        'Conflict resolved'
      );
    });
  }

  /**
   * Get all records with conflicts
   */
  async getConflicts(): Promise<ShadowRecordWithPm[]> {
    const result = await this.listShadowRecords({ syncStatus: 'CONFLICT' });
    return result.data;
  }

  // ===========================================================================
  // Statistics
  // ===========================================================================

  /**
   * Get sync statistics
   */
  async getSyncStats(): Promise<SyncStats> {
    return this.traced('getSyncStats', async () => {
      const stats = await this.db
        .select({
          status: maximoShadowRecords.syncStatus,
          count: count(),
        })
        .from(maximoShadowRecords)
        .groupBy(maximoShadowRecords.syncStatus);

      const statusCounts = stats.reduce(
        (acc, s) => {
          acc[s.status] = s.count;
          return acc;
        },
        {} as Record<string, number>
      );

      // Get last sync timestamp
      const lastSync = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.syncStatus, 'SYNCED'),
        orderBy: [desc(maximoShadowRecords.lastSyncAt)],
      });

      return {
        pendingRecords: statusCounts['PENDING'] ?? 0,
        syncedRecords: statusCounts['SYNCED'] ?? 0,
        conflictRecords: statusCounts['CONFLICT'] ?? 0,
        errorRecords: statusCounts['ERROR'] ?? 0,
        lastSyncAt: lastSync?.lastSyncAt ?? undefined,
        lastPullAt: this.lastPullTimestamp ?? undefined,
        circuitBreakerState: this.circuitBreaker.getState(),
      };
    });
  }

