   364→ */
   365→pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   366→  const requestId = getRequestId(c);
   367→  const pmId = c.req.param('id');
   368→
   369→  if (!isValidUuid(pmId)) {
