   371→  }
   372→
   373→  const body = await c.req.json();
   374→
   375→  // Validate reason is provided
   376→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   377→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   378→  }
   379→
   380→  // Validate targetDate if provided
