   382→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   383→  }
   384→
   385→  // Validate assignedTrackId if provided
   386→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   387→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   388→  }
   389→
   390→  const service = getService();
