   392→
   393→  // Get current PM to capture old values
   394→  const currentPm = await service.getPm(pmId);
   395→
   396→  // Only proceed if targetDate is being changed
   397→  if (!body.targetDate) {
   398→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
   399→  }
   400→
   401→  const request: MovePmRequest = {
